import React, { useState } from "react";
import FormContainer from "./components/FormContainer";

function App() {
  const [showRegister, setShowRegister] = useState(false);

  return (
    <div className={`container ${showRegister ? "active" : ""}`}>
      <FormContainer showRegister={showRegister} setShowRegister={setShowRegister} />
    </div>
  );
}

export default App;
